request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?modelId WHERE {
  ?model a bboExt:Model .
  ?model bbo:name ?modelName .
  OPTIONAL { ?model tai:originalId ?modelId . }
  OPTIONAL { ?model tai:normalizedId ?modelId . }
  FILTER(CONTAINS(STR(?modelId), "0b4394edaa09437d93cc54c78c0180cb") || CONTAINS(STR(?model), "0b4394edaa09437d93cc54c78c0180cb"))
}
LIMIT 10

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?gw ?gwName ?dir WHERE {
  ?choreo a bboExt:Choreography .
  ?choreo tai:belongsTo ?defs .
  ?defs a bboExt:Definitions .
  ?defs tai:belongsTo ?model .
  ?model tai:originalId "0b4394edaa09437d93cc54c78c0180cb" .
  { ?gw a bboExt:ParallelGateway . }
  UNION
  { ?gw a bboExt:ExclusiveGateway . }
  ?gw tai:belongsTo ?choreo .
  OPTIONAL { ?gw bbo:name ?gwName . }
  OPTIONAL { ?gw bboExt:gatewayDirection ?dir . }
}
LIMIT 25
